1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	
21	const groupByType = (items: Item[]): Item[][] => {
22	  const groups = new Map<string, Item[]>();
23	  for (const item of items) {
24	    const group = groups.get(item.type) ?? [];
25	    group.push(item);
26	    groups.set(item.type, group);
27	  }
28	  return [...groups.values()];
29	};
30	
31	const sumOfBasePremiums = (items: Item[]): number =>
32	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
33	
34	const basePremiumForGroup = (group: Item[]): number =>
35	  group.length === COMPONENT_BLOCK_SIZE
36	    ? COMPONENT_BLOCK_PREMIUM
37	    : sumOfBasePremiums(group);
38	
39	const totalBasePremium = (items: Item[]): number =>
40	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
41	
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const FIRST_INSURANCE_RATE = 0.1;
44	
45	const curseSurcharge = (items: Item[]): number =>
46	  items
47	    .filter((item) => item.cursed)
48	    .reduce((sum, item) => sum + basePremiumFor(item) * CURSE_SURCHARGE_RATE, 0);
49	
50	const firstInsuranceSurcharge = (items: Item[]): number =>
51	  totalBasePremium(items) * FIRST_INSURANCE_RATE;
52	
53	const premiumFor = (items: Item[]): number =>
54	  Math.ceil(
55	    totalBasePremium(items) +
56	      curseSurcharge(items) +
57	      firstInsuranceSurcharge(items) +
58	      PROCESSING_FEE,
59	  );
60	
61	const resultFor = (step: QuoteStep) => ({ premium: premiumFor(step.items) });
62	
63	export const runScenario = (input: unknown): unknown => {
64	  const scenario = input as Scenario;
65	  return { results: scenario.steps.map(resultFor) };
66	};
